from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismSendCmdNode(BaseNode):
    name = "Prism: Send Cmd to DCC"
    category = "DCCs"

    def __init__(self):
        super().__init__()
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("target_dcc", "string", widget_type="dropdown", options=["Houdini","Maya","Blender","Nuke","3dsMax","Unreal","SubstancePainter","Photoshop"], default="Houdini")
        self.add_input("python_code", "string", widget_type="text_area", default="print('hello from Vibrante')")
        self.add_output("success", "bool")
        self.add_output("result", "any")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        dcc = inputs.get('target_dcc') or ''
        code = inputs.get('python_code') or ''
        if core is None or not dcc or not code:
            self.log_error("Need core, target_dcc and python_code.")
            return {'success': False, 'result': None}
        try:
            plugin = core.getPlugin('PrismInternals') if hasattr(core, 'getPlugin') else core.plugins.getPlugin('PrismInternals')
            if plugin is None:
                self.log_error("PrismInternals plugin not loaded.")
                return {'success': False, 'result': None}
            internals = getattr(plugin, 'internals', plugin)
            if not hasattr(internals, 'sendCmd'):
                self.log_error("sendCmd not available on PrismInternals.")
                return {'success': False, 'result': None}
            result = internals.sendCmd(dcc, code)
            self.log_success(f"sendCmd -> {dcc}: ok")
            await self.set_output('exec_out', True)
            return {'success': True, 'result': result}
        except Exception as e:
            self.log_error(f"sendCmd failed: {e}")
            return {'success': False, 'result': None}

def register_node():
    return PrismSendCmdNode
